CREATE OR REPLACE FUNCTION fpa_com_chk_id_card (as_id_card char) RETURNS bigint AS $body$
DECLARE

  li_num  bigint := 0;
  li_sum  bigint := 0;
  ls_return char(1);
BEGIN
  if length(trim(both as_id_card)) = 13 then
    for i in 1..12 loop
      li_num  := 0;
      li_num  := substr(trim(both as_id_card),i,1);
      li_num  := li_num * (14 - i);
      li_sum  := li_sum + li_num;
    end loop;
      li_sum := 11 - mod(li_sum,11);
   else
      CALL spa_dberror('Invalid id_card');
   end if;

  if li_sum = substr(trim(both as_id_card),13,1) then
    ls_return := '1';
  else
    ls_return := '0';
  end if;

  return ls_return;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
